# Base shape classes and interfaces for geometry

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

interface IMeasurable:
    def get_dimensions(self) -> str:
        ...

